// ── Book Cover Service ──────────────────────────────────────────────────────
// Uses Open Library API to fetch real book covers

/**
 * Get book cover URL from Open Library API
 * Tries: ISBN > Title+Author > Default placeholder
 */
export const getBookCoverUrl = async (book) => {
  if (book.coverUrl) return book.coverUrl; // Use provided URL first

  // Try ISBN first (most reliable)
  if (book.isbn) {
    const isbnUrl = getOpenLibraryCoverUrl({ isbn: book.isbn });
    if (await isImageValid(isbnUrl)) {
      return isbnUrl;
    }
  }

  // Try title + author (fallback)
  if (book.title && book.author) {
    const titleUrl = getOpenLibraryCoverUrl({ 
      title: book.title, 
      author: book.author 
    });
    if (await isImageValid(titleUrl)) {
      return titleUrl;
    }
  }

  // Try just title
  if (book.title) {
    const titleOnlyUrl = getOpenLibraryCoverUrl({ title: book.title });
    if (await isImageValid(titleOnlyUrl)) {
      return titleOnlyUrl;
    }
  }

  return null; // No cover found
};

/**
 * Build Open Library cover URL
 * https://covers.openlibrary.org/b/{identifier_type}/{identifier}-{size}.jpg
 */
export const getOpenLibraryCoverUrl = (searchParams) => {
  const baseUrl = 'https://covers.openlibrary.org/b';
  
  if (searchParams.isbn) {
    return `${baseUrl}/isbn/${searchParams.isbn}-M.jpg`;
  }
  
  // Search by title/author via Open Library API
  const query = buildSearchQuery(searchParams);
  return `${baseUrl}/query?${query}`;
};

/**
 * Build Open Library search query
 */
function buildSearchQuery(params) {
  const parts = [];
  if (params.title) parts.push(`title=${encodeURIComponent(params.title)}`);
  if (params.author) parts.push(`author=${encodeURIComponent(params.author)}`);
  parts.push('limit=1');
  return parts.join('&');
}

/**
 * Check if an image URL is valid (returns 200 and is an image)
 */
async function isImageValid(url) {
  try {
    const response = await fetch(url, { method: 'HEAD' });
    return response.ok && response.headers.get('content-type')?.includes('image');
  } catch {
    return false;
  }
}

/**
 * Search Open Library for a book by title/author
 * Returns cover data suitable for BookCard
 */
export const searchOpenLibrary = async (query) => {
  try {
    const response = await fetch(
      `https://openlibrary.org/search.json?${query}`
    );
    if (!response.ok) return null;
    
    const data = await response.json();
    if (!data.docs || data.docs.length === 0) return null;
    
    const book = data.docs[0];
    return {
      title: book.title,
      author: book.author_name?.[0] || 'Unknown',
      isbn: book.isbn?.[0],
      year: book.first_publish_year,
      coverUrl: book.cover_id 
        ? `https://covers.openlibrary.org/b/id/${book.cover_id}-M.jpg`
        : null
    };
  } catch {
    return null;
  }
};
